def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            if capacity == 0:
                priorities[i] = np.inf
            else:
                priorities[i] = -np.inf
            continue
        ratio = item / capacity
        sum_weights = 0
        for power in range(1, 6):
            weight = (-1)**power * (power / (power + 1))
            term = (ratio ** power) * weight
            if term > 1e3:
                term = np.log1p(term)
            sum_weights += term
        if ratio > 2:
            priorities[i] = sum_weights * np.exp(-ratio)
        elif 1.5 < ratio <= 2:
            priorities[i] = sum_weights + np.sqrt(ratio)
        elif 1 <= ratio <= 1.5:
            temp = 0
            for n in range(1, 4):
                temp += np.sin(ratio * n) / (n+1)
            priorities[i] = sum_weights + temp
        else:
            if sum_weights < 0.1:
                priorities[i] = -np.log1p(abs(sum_weights)) * (ratio ** 2)
            else:
                priorities[i] = -np.log(abs(sum_weights) + 1) / (ratio + 1)
        if priorities[i] < 0:
            priorities[i] = abs(priorities[i]) ** 0.5
    return priorities
